import React from 'react';

const LockedFeatureCard = ( { icon, title, description, value, actionLabel = 'Upgrade to View' }: {
    icon: React.ReactNode;
    title: string;
    description: string;
    value?: string | number;
    actionLabel?: string;
} ) => {
	const hasValue = value !== undefined && value !== null;

	return (
		<div className="bg-white rounded-xl border border-gray-100 p-6">
			<div className="flex items-center gap-2 mb-3">
				{icon}
				<span className="text-lg text-thumbpress-title">{ title }</span>
			</div>

			<div className={ `flex mb-1 ${ hasValue ? 'gap-5 items-center' : 'gap-3 items-start' }` }>
				<p className="text-3xl font-medium text-thumbpress-title">{ hasValue ? value : '****' }</p>
				<a href="#/pro" className='!text-[#FB8005] border-b border-[#FB8005] text-sm'>{ actionLabel }</a>
			</div>

			<p className="text-base text-[#777980]">{ description }</p>
		</div>
	);
};

export default LockedFeatureCard;
