export default function Dashboard() {
	const [stats, setStats] = useState<DashboardStats | null>(null);
	const [loading, setLoading] = useState(true);
	const navigate = useNavigate();

	useEffect(() => {
		getDashboardStats()
			.then((res: any) => {
				if (res?.data) {
					setStats(res.data);
				}
			})
			.finally(() => setLoading(false));
	}, []);

	if (loading) {
		return <DashboardSkeleton />;
	}

	if (!stats) {
		return (
			<>
				<Header title="Dashboard" />
				<PluginPage></PluginPage>
			</>
		);
	}

	return (
		<>
			<Header title="Dashboard" />

			<PluginPage>
				{/* Top row: Health Score + Total Images + Total Thumbnails */}
				<div className="grid grid-cols-1 md:grid-cols-[1fr_auto] gap-5 mb-5">
					<HealthScoreCard score={stats.health_score} stats={stats} />

					<div className="grid grid-cols-2 gap-5 min-w-[826px]">
						<InfoCard
							customIcon={<TotalImagesIcon />}
							title="Total Images"
							value={stats.total_images.toLocaleString()}
							sub="In media library"
						/>
						<InfoCard
							customIcon={<TotalThumbnailsIcon />}
							title="Total Thumbnails"
							value={stats.total_thumbnails.toLocaleString()}
							sub="Thumbnails found"
						/>
						<InfoCard
							customIcon={<UnoptimizedIcon />}
							title="Unoptimized Images"
							value={stats.unoptimized_images.toLocaleString()}
							sub="Images yet to be fixed"
						/>
						<InfoCard
							customIcon={<SpaceSavedIcon />}
							title="Space Saved"
							value={formatBytes(stats.total_space_saved)}
							sub="Worth of space saved"
						/>
					</div>
				</div>

				{/* Feature Cards Grid */}
				<div className="grid grid-cols-2 md:grid-cols-4 gap-5">
					{
						applyFilters(
							'thumbpress_dashboard_pro_cards',
							<>
								<LockedFeatureCard
									icon={<LargeImagesIcon />}
									title="Large Images"
									description="Images (over 1 MB)"
									value={(stats.large_images ?? 0).toLocaleString()}
									actionLabel="Upgrade to Compress"
								/>
								<LockedFeatureCard
									icon={<UnusedImagesIconPro />}
									title="Unused Images"
									description="Unattached images"
								/>
								<LockedFeatureCard
									icon={<CompressedImagesIcon />}
									title="Compress Images"
									description="Images needs compression"
									value={(stats.not_compressed ?? 0).toLocaleString()}
									actionLabel="Upgrade to Compress"
								/>
								<LockedFeatureCard
									icon={<DuplicateImagesIcon />}
									title="Duplicate Images"
									description="Duplicate images found"
									value={(stats.duplicate_images ?? 0).toLocaleString()}
									actionLabel="Upgrade to Merge"
								/>
								<LockedFeatureCard
									icon={<AvifFileIcon />}
									title="Convert to AVIF"
									description="Non-AVIF images found"
									value={(stats.not_avif ?? 0).toLocaleString()}
									actionLabel="Upgrade to Convert"
								/>
							</>,
							stats,
							navigate,
						) as React.ReactNode
					}

					<InfoCard
						customIcon={<WebpFileIcon />}
						title="Convert to WebP"
						value={(stats.not_webp ?? 0).toLocaleString()}
						sub="Non-WebP images found"
						onClick={() => navigate('/convert-to-webp')}
					/>

					<InfoCard
						customIcon={<ThumbnailDisabledIcon />}
						title="Thumbnail Disabled"
						value={`${stats.disabled_sizes}/${stats.total_sizes}`}
						sub="These sizes won't be generated"
						onClick={() => navigate('/settings?tab=thumbnails')}
					/>

					<InfoCard
						customIcon={<LazyLoadingIcon />}
						title="Lazy Loading"
						value={stats.lazy_load ? 'Active' : 'Inactive'}
						sub={`Status: ${stats.lazy_load ? 'On' : 'Off'}`}
						onClick={() => navigate('/settings?tab=general')}
					/>
				</div>
			</PluginPage>
		</>
	);
}
